import { createClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";
import { corsHeaders, handleCors } from "./_shared/cors.ts";
import {
  getBearerClient,
  userHasManageCategories,
} from "./_shared/evolutionAuth.ts";

const SETTINGS_KEY = "evolution_instance_name";

function evoBase(): string {
  const u = (Deno.env.get("EVOLUTION_BASE_URL") ?? "").replace(/\/$/, "");
  return u;
}

function evoHeaders(): HeadersInit {
  return {
    apikey: Deno.env.get("EVOLUTION_API_KEY") ?? "",
    "Content-Type": "application/json",
  };
}

async function getInstanceName(
  admin: ReturnType<typeof createClient>,
): Promise<string> {
  const { data } = await admin
    .from("app_c009c0e4f1_integration_settings")
    .select("value")
    .eq("key", SETTINGS_KEY)
    .maybeSingle();
  const fromDb = data?.value?.trim();
  if (fromDb) return fromDb;
  return (Deno.env.get("EVOLUTION_INSTANCE_NAME") ?? "").trim();
}

async function evoFetch(path: string, init?: RequestInit): Promise<Response> {
  const base = evoBase();
  if (!base) {
    return new Response(
      JSON.stringify({ error: "EVOLUTION_BASE_URL não configurada" }),
      { status: 500 },
    );
  }
  const url = `${base}${path}`;
  return fetch(url, {
    ...init,
    headers: {
      ...evoHeaders(),
      ...(init?.headers ?? {}),
    },
  });
}

Deno.serve(async (req) => {
  const cors = handleCors(req);
  if (cors) return cors;

  try {
    const { error: authErr, authUserId } = await getBearerClient(req);
    if (authErr || !authUserId) {
      return new Response(JSON.stringify({ error: authErr ?? "Não autorizado" }), {
        status: 401,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const supabaseUrl = Deno.env.get("SUPABASE_URL") ?? "";
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";
    const admin = createClient(supabaseUrl, serviceKey);

    const allowed = await userHasManageCategories(admin, authUserId);
    if (!allowed) {
      return new Response(
        JSON.stringify({ error: "Sem permissão para gerenciar categorias" }),
        {
          status: 403,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        },
      );
    }

    const body = req.method === "POST" || req.method === "PUT"
      ? await req.json().catch(() => ({}))
      : {};

    const action = (body as { action?: string }).action;

    if (action === "saveInstanceName") {
      const name = String((body as { instanceName?: string }).instanceName ?? "")
        .trim();
      if (!name) {
        return new Response(
          JSON.stringify({ error: "Nome da instância obrigatório" }),
          {
            status: 400,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          },
        );
      }
      const { error: upErr } = await admin.from(
        "app_c009c0e4f1_integration_settings",
      ).upsert({
        key: SETTINGS_KEY,
        value: name,
        updated_at: new Date().toISOString(),
      }, { onConflict: "key" });
      if (upErr) {
        return new Response(JSON.stringify({ error: upErr.message }), {
          status: 500,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        });
      }
      return new Response(JSON.stringify({ ok: true, instanceName: name }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    if (action === "createInstance") {
      const name = String((body as { instanceName?: string }).instanceName ?? "")
        .trim();
      if (!name) {
        return new Response(
          JSON.stringify({ error: "Nome da instância obrigatório" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } },
        );
      }
      const res = await evoFetch("/instance/create", {
        method: "POST",
        body: JSON.stringify({
          instanceName: name,
          integration: "WHATSAPP-BAILEYS",
          qrcode: false,
        }),
      });
      const json = await res.json().catch(() => ({}));
      if (!res.ok) {
        return new Response(
          JSON.stringify({
            error: "Falha ao criar instância na Evolution",
            details: json,
          }),
          {
            status: 502,
            headers: { ...corsHeaders, "Content-Type": "application/json" },
          },
        );
      }
      await admin.from("app_c009c0e4f1_integration_settings").upsert({
        key: SETTINGS_KEY,
        value: name,
        updated_at: new Date().toISOString(),
      }, { onConflict: "key" });
      return new Response(JSON.stringify({ ok: true, evolution: json }), {
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    const instance = await getInstanceName(admin);
    if (!instance) {
      return new Response(
        JSON.stringify({
          error:
            "Nome da instância não configurado. Informe e salve na tela de categorias.",
        }),
        {
          status: 400,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        },
      );
    }

    if (action === "connectionState") {
      const res = await evoFetch(
        `/instance/connectionState/${encodeURIComponent(instance)}`,
        { method: "GET" },
      );
      const json = await res.json().catch(() => ({}));
      return new Response(JSON.stringify(json), {
        status: res.ok ? 200 : 502,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    if (action === "getQr") {
      const res = await evoFetch(
        `/instance/connect/${encodeURIComponent(instance)}`,
        { method: "GET" },
      );
      const json = await res.json().catch(() => ({}));
      return new Response(JSON.stringify(json), {
        status: res.ok ? 200 : 502,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    if (action === "listChats") {
      const res = await evoFetch(
        `/chat/findChats/${encodeURIComponent(instance)}`,
        {
          method: "POST",
          body: JSON.stringify({}),
        },
      );
      const raw = await res.json().catch(() => ({}));
      const list = Array.isArray(raw)
        ? raw
        : (raw as { chats?: unknown[] }).chats ??
          (raw as { response?: unknown[] }).response ??
          [];

      const chats = (list as Record<string, unknown>[]).map((c) => {
        const jid = String(
          c.remoteJid ?? c.id ?? (c.key as Record<string, string>)?.remoteJid ??
            "",
        );
        const name = String(
          c.pushName ?? c.name ?? c.subject ?? jid ?? "Chat",
        );
        return { jid, name };
      }).filter((c) => c.jid);

      return new Response(JSON.stringify({ chats, raw }), {
        status: res.ok ? 200 : 502,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      });
    }

    return new Response(
      JSON.stringify({ error: "action inválida", valid: ["connectionState", "getQr", "listChats", "saveInstanceName", "createInstance"] }),
      { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } },
    );
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return new Response(JSON.stringify({ error: msg }), {
      status: 500,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  }
});

export const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
};

export function handleCors(req: Request): Response | null {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }
  return null;
}

import { createClient, SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";

export async function getBearerClient(req: Request): Promise<{
  error: string | null;
  authUserId: string | null;
  userClient: SupabaseClient | null;
}> {
  const supabaseUrl = Deno.env.get("SUPABASE_URL") ?? "";
  const supabaseAnonKey = Deno.env.get("SUPABASE_ANON_KEY") ?? "";
  const authHeader = req.headers.get("Authorization");
  if (!authHeader) {
    return { error: "Authorization ausente", authUserId: null, userClient: null };
  }
  const userClient = createClient(supabaseUrl, supabaseAnonKey, {
    global: { headers: { Authorization: authHeader } },
  });
  const { data: { user }, error } = await userClient.auth.getUser();
  if (error || !user) {
    return { error: "Sessão inválida", authUserId: null, userClient: null };
  }
  return { error: null, authUserId: user.id, userClient };
}

export async function userHasManageCategories(
  admin: SupabaseClient,
  authUserId: string,
): Promise<boolean> {
  const { data: profile } = await admin
    .from("app_c009c0e4f1_users")
    .select("id, role")
    .eq("auth_user_id", authUserId)
    .maybeSingle();
  if (!profile) return false;
  const roleStr = String(profile.role ?? "").toLowerCase().trim();
  if (roleStr === "admin") return true;
  const { data: roleRow } = await admin
    .from("app_c009c0e4f1_roles")
    .select("id")
    .eq("key", roleStr)
    .maybeSingle();
  if (!roleRow) return false;
  const { data: perm } = await admin
    .from("app_c009c0e4f1_role_permissions")
    .select("permission_key")
    .eq("role_id", roleRow.id)
    .eq("permission_key", "manage_categories")
    .maybeSingle();
  return !!perm;
}

export async function canInvokeTicketNotify(
  admin: SupabaseClient,
  authUserId: string,
  ticketCreatedBy: string,
): Promise<boolean> {
  const { data: profile } = await admin
    .from("app_c009c0e4f1_users")
    .select("id, role")
    .eq("auth_user_id", authUserId)
    .maybeSingle();
  if (!profile) return false;
  if (profile.id === ticketCreatedBy) return true;
  const roleStr = String(profile.role ?? "").toLowerCase().trim();
  return ["admin", "support", "lawyer"].includes(roleStr);
}
